// Dedup: check if this messageSid was already processed
const sid = $input.first().json?.data?.messageSid;
if (!sid) return []; // no sid = skip

// Pass through - the Wait node debounce handles timing
// This node ensures we only process unique message IDs
const seen = $getWorkflowStaticData('global');
if (seen[sid]) {
  return []; // Already processed, skip
}
seen[sid] = Date.now();

// Cleanup old entries (keep last 100)
const keys = Object.keys(seen);
if (keys.length > 100) {
  const oldest = keys.slice(0, keys.length - 100);
  oldest.forEach(k => delete seen[k]);
}

return [$input.first()];

// Get data from upstream nodes
const phone = $('Wait for Text Response').item.json.data.from;
const summary = $('Summarize Transcript').item.json.output.summary || '';
const prospectName = $('Summarize Transcript').item.json.output.prospect_name || '';

// Determine type_projet
const isVendeur = summary.toLowerCase().includes('vendeur') || summary.toLowerCase().includes('vente');
const typeProjet = isVendeur ? 'vendeur' : 'acheteur';

// Extract prenom/nom from prospect_name (LLM extracted)
const blacklist = ['nadia', 'joanel', 'assistante', 'assistant', 'courtier'];
let prenom = '';
let nom = '';
if (prospectName && !blacklist.includes(prospectName.toLowerCase().split(/\s+/)[0])) {
  const parts = prospectName.trim().split(/\s+/);
  prenom = parts[0] || '';
  nom = parts.slice(1).join(' ') || '';
}

// Score from summary keywords
let score = 7;
if (summary.toLowerCase().includes('urgent') || summary.toLowerCase().includes('divorce') || summary.toLowerCase().includes('d\u00e9c\u00e8s')) {
  score = 9;
} else if (summary.toLowerCase().includes('pr\u00e9-approuv') || summary.toLowerCase().includes('pre-approv')) {
  score = 8;
} else if (summary.toLowerCase().includes('exploration') || summary.toLowerCase().includes('juste regarde')) {
  score = 3;
}

// Detect language
const isEnglish = summary.toLowerCase().includes('anglophone') || summary.toLowerCase().includes('english');
const langue = isEnglish ? 'en' : 'fr';

// Escape single quotes
const esc = (s) => s.replace(/'/g, "''");

const query = `
INSERT INTO prospects (
  canal_source, statut, telephone, courtier_id, type_projet,
  score_chaleur, nom, prenom, langue_preferee, resume_ia, created_at, updated_at
)
VALUES (
  'sms', 'qualifie', '${esc(phone)}',
  (SELECT id FROM courtiers LIMIT 1),
  '${typeProjet}', ${score}, '${esc(nom)}', '${esc(prenom)}', '${langue}',
  '${esc(summary)}',
  NOW(), NOW()
)
ON CONFLICT (telephone) WHERE telephone IS NOT NULL
DO UPDATE SET
  statut = 'qualifie',
  score_chaleur = ${score},
  type_projet = '${typeProjet}',
  nom = CASE WHEN '${esc(nom)}' != '' THEN '${esc(nom)}' ELSE prospects.nom END,
  prenom = CASE WHEN '${esc(prenom)}' != '' THEN '${esc(prenom)}' ELSE prospects.prenom END,
  langue_preferee = '${langue}',
  resume_ia = '${esc(summary)}',
  updated_at = NOW()
RETURNING id, telephone, statut, prenom, nom, score_chaleur, resume_ia, created_at;
`;

return [{ json: { query, phone, typeProjet, prenom, nom, score, langue, summary: esc(summary) } }];

// Calculate human-like typing delay based on response length
const output = $json.output || '';
const charCount = output.length;

// readTime (3s) + typing proportional to length + random jitter
const readTime = 3;
const jitter = Math.random() * 5;
let delay = Math.round(readTime + (charCount * 0.15) + jitter);

// Clamp between 5 and 50 seconds
delay = Math.max(5, Math.min(50, delay));

return [{ json: { _delay: delay, output: $json.output } }];
